--drop view [dbo].[SecurityHierarchyView];
CREATE view [dbo].[ArrangementHierarchyView]
AS
    with tbl AS
             (
                 select st.ArrangementID           'id'
                      , st.ArrangementID 'name'
                      , sxs.ParentArrangementID    'ParentID'
                 from ArrangementXArrangement sxs (nolock)
                          right outer join Arrangement st (nolock)
                                           on sxs.ChildArrangementID = st.ArrangementID
                          left join Arrangement stChild (nolock)
                                    on sxs.ChildArrangementID = stChild.ArrangementID

             ),
         SecurityPath
             AS (
             -- anchor
             SELECT id,
                    [Name],
                    ParentID,
                    CAST(([Name]) AS VARCHAR(1000)) AS "Pather",
                    CAST((id) AS VARCHAR(1000))     AS "Path"
             FROM tbl
             WHERE ParentId IS NULL
             UNION ALL
             --recursive member
             SELECT t.id,
                    t.[Name],
                    t.ParentID,
                    CAST((a.name + '/' + t.Name) AS VARCHAR(1000))                       AS "Path",
                    CAST((a."Path" + '/' + cast(t.id as varchar(max))) AS VARCHAR(1000)) AS "PathCrypt"
             FROM tbl AS t
                      JOIN SecurityPath AS a
                           ON t.ParentId = a.id
         )
    SELECT s.id,s.Name,s.ParentID,s.Pather,s.Path,'1' as 'One'
    FROM SecurityPath s
GO
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
