-- =============================================
-- Author:		Marc Magon
-- Create date: 2013/07/31
-- Description:	This procedure will get all database dictionary fields
-- =============================================
CREATE PROCEDURE [dbo].[GetDatabaseDictionary]
AS
BEGIN
    SELECT OBJECT_NAME(ISNULL(col.object_id, major_id)) ObjectName, ISNULL(col.name, 'TableDefinition'), ep.name, ep.value
    FROM sys.columns col
             FULL OUTER JOIN sys.extended_properties ep
                             ON col.object_id = ep.major_id
                                 AND col.column_id = ep.minor_id
    WHERE ep.name = 'MS_Description'
       or ep.name is null
        --WHERE OBJECT_NAME(col.object_id) = 'IP_X_IP_NM_TP'
        --OR OBJECT_NAME(ep.major_id) = 'IP_X_IP_NM_TP'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sql%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysa%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysb%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysc%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysd%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'syse%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysf%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysg%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysh%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysi%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysj%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysk%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysl%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysm%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysn%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'syso%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'syso%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysp%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysq%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysr%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'syss%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'systyp%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysu%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysw%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'sysx%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'plan_%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'queue_%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'filestream_%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'filetable_%'
        and OBJECT_NAME(ISNULL(col.object_id, major_id)) not like 'FK_%'
    ORDER BY ep.value, OBJECT_NAME(ISNULL(col.object_id, major_id)), col.column_id

END



GO
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Marc Magon
-- Create date: 2013/07/31
-- Description:	This procedure will get all database dictionary fields for a particular table
-- =============================================
CREATE PROCEDURE [dbo].[GetDatabaseDictionaryForAllTables]
AS
BEGIN
    SELECT OBJECT_NAME(ISNULL(col.object_id, major_id)) TableName,
           --ISNULL(col.name,'TableDefinition'),ep.name,
           value
    FROM sys.columns col
             FULL OUTER JOIN sys.extended_properties ep
                             ON col.object_id = ep.major_id
                                 AND col.column_id = ep.minor_id
    WHERE (ep.name = 'MS_Description' or ep.name is null)
      and col.name is null
      --WHERE OBJECT_NAME(col.object_id) = 'IP_X_IP_NM_TP'
      --OR OBJECT_NAME(ep.major_id) = 'IP_X_IP_NM_TP'
    ORDER BY OBJECT_NAME(ISNULL(col.object_id, major_id)), col.column_id
END



GO
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		Marc Magon
-- Create date: 2013/07/31
-- Description:	This procedure will get all database
--				dictionary fields for a particular table
-- =============================================
CREATE PROCEDURE [dbo].[GetDatabaseDictionaryForTable] @TableName varchar(250)
AS
BEGIN
    SELECT OBJECT_NAME(ISNULL(col.object_id, major_id)) ObjectName, ISNULL(col.name, 'TableDefinition'), ep.name, value
    FROM sys.columns col
             FULL OUTER JOIN sys.extended_properties ep
                             ON col.object_id = ep.major_id
                                 AND col.column_id = ep.minor_id
    WHERE (ep.name = 'MS_Description' or ep.name is null)
      and OBJECT_NAME(ISNULL(col.object_id, major_id)) = @TableName
      --and col.name is null
      --WHERE OBJECT_NAME(col.object_id) = 'IP_X_IP_NM_TP'
      --OR OBJECT_NAME(ep.major_id) = 'IP_X_IP_NM_TP'
    ORDER BY OBJECT_NAME(ISNULL(col.object_id, major_id)), col.column_id
END



