-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[UpdateHierarchyAll]
AS
BEGIN
    UPDATE SecurityHierarchy
    SET Path = v.Path,
        ParentID = v.ParentID,
        Pather = v.Pather
    FROM SecurityHierarchy (nolock) sh
             inner join SecurityHierarchyView (nolock) v
                        on sh.id = v.id
    where sh.Path <> v.Path
END
